scripts.script:
var cellCount = 10000

// A heatmap is a rows x cols matrix; each cell is one value. The cell count
// is what scales cost, so map a target cell count to a rows/cols shape.
function shapeFor(cells) {
  if (cells <= 10000) return { rows: 50, cols: cells / 50 }
  return { rows: 100, cols: cells / 100 }
}

function generateHeatmap(cells) {
  var shape = shapeFor(cells)
  var series = new Array(shape.rows)
  for (var r = 0; r < shape.rows; r++) {
    var data = new Array(shape.cols)
    for (var c = 0; c < shape.cols; c++) {
      data[c] = { x: c, y: Math.round(Math.random() * 100) }
    }
    series[r] = { name: 'r' + r, data: data }
  }
  return series
}

var heatmapData = generateHeatmap(cellCount)

// Stateless helper shared by the vanilla, React and Vue builds.
function domNodeCount() {
  var el = document.querySelector('#chart')
  return el ? el.getElementsByTagName('*').length : 0
}

chart.options:
chart: {
  height: 500,
  type: 'heatmap',
  renderer: 'canvas',
  rendererThreshold: 8000,
  animations: { enabled: false },
  toolbar: { show: false },
},
title: {
  text: 'Heatmap: 10,000 cells',
  align: 'left',
},
subtitle: {
  text: 'Each cell is one SVG rect; use the controls to scale the cell count',
  align: 'left',
},
dataLabels: { enabled: false },
xaxis: {
  type: 'category',
  labels: { show: false },
  axisTicks: { show: false },
},

vanilla-js-script:
// cellCount, heatmapData, generateHeatmap, shapeFor and domNodeCount come from
// the shared head script; updateStats and lastRenderMs are chart-bound so they
// live here.
var lastRenderMs = 0

function updateStats() {
  var el = document.getElementById('stats')
  if (!el || typeof chart === 'undefined') return
  var active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
  el.innerHTML =
    'Cells: ' +
    cellCount.toLocaleString() +
    '  ·  Active renderer: ' +
    active.toUpperCase() +
    '  ·  DOM nodes in chart: ' +
    domNodeCount().toLocaleString() +
    '  ·  Render: ' +
    (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
    ''
}

requestAnimationFrame(function poll() {
  if (chart && chart.w && chart.w.globals && chart.w.globals.series) {
    updateStats()
  } else {
    requestAnimationFrame(poll)
  }
})

function rebuild() {
  cellCount = parseInt(document.getElementById('cellCount').value, 10)
  var mode = document.getElementById('rendererMode').value

  heatmapData = generateHeatmap(cellCount)
  options.chart.renderer = mode
  options.series = heatmapData
  options.title.text = 'Heatmap: ' + cellCount.toLocaleString() + ' cells'

  var t = performance.now()
  chart.destroy()
  chart = new ApexCharts(document.querySelector('#chart'), options)
  chart.render().then(function () {
    lastRenderMs = Math.round(performance.now() - t)
    updateStats()
  })
}

document.getElementById('rerender').addEventListener('click', rebuild)
document.getElementById('rendererMode').addEventListener('change', rebuild)
document.getElementById('cellCount').addEventListener('change', rebuild)

react-script:
React.useEffect(() => {
  // This demo destroys and recreates the chart on every control change, so it
  // skips the react-apexcharts wrapper and creates the instance in #chart
  // directly, like the vanilla build. cellCount, heatmapData, generateHeatmap,
  // shapeFor and domNodeCount live in the shared head script.
  let lastRenderMs = 0
  let chart = null
  let disposed = false

  const options = Object.assign({ series: state.series }, state.options)
  options.chart = Object.assign({}, state.options.chart)
  options.title = Object.assign({}, state.options.title)

  function updateStats() {
    const el = document.getElementById('stats')
    if (!el || !chart) return
    const active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
    el.innerHTML =
      'Cells: ' +
      cellCount.toLocaleString() +
      '  ·  Active renderer: ' +
      active.toUpperCase() +
      '  ·  DOM nodes in chart: ' +
      domNodeCount().toLocaleString() +
      '  ·  Render: ' +
      (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
      ''
  }

  function rebuild() {
    cellCount = parseInt(document.getElementById('cellCount').value, 10)
    const mode = document.getElementById('rendererMode').value

    heatmapData = generateHeatmap(cellCount)
    options.chart.renderer = mode
    options.series = heatmapData
    options.title.text = 'Heatmap: ' + cellCount.toLocaleString() + ' cells'

    const t = performance.now()
    if (chart) chart.destroy()
    chart = new ApexCharts(document.querySelector('#chart'), options)
    chart.render().then(function () {
      if (disposed) return
      lastRenderMs = Math.round(performance.now() - t)
      updateStats()
    })
  }

  document.getElementById('rerender').addEventListener('click', rebuild)
  document.getElementById('rendererMode').addEventListener('change', rebuild)
  document.getElementById('cellCount').addEventListener('change', rebuild)

  chart = new ApexCharts(document.querySelector('#chart'), options)
  chart.render().then(function () {
    if (disposed) return
    updateStats()
  })

  return () => {
    disposed = true
    if (chart) chart.destroy()
  }
}, [])

vue-script:
mounted: function () {
  // This demo destroys and recreates the chart on every control change, so it
  // skips the vue-apexcharts wrapper and creates the instance in #chart
  // directly, like the vanilla build. cellCount, heatmapData, generateHeatmap,
  // shapeFor and domNodeCount live in the shared head script.
  var me = this
  var lastRenderMs = 0
  var chart = null

  var options = Object.assign({ series: me.series }, me.chartOptions)
  options.chart = Object.assign({}, me.chartOptions.chart)
  options.title = Object.assign({}, me.chartOptions.title)

  function updateStats() {
    var el = document.getElementById('stats')
    if (!el || !chart) return
    var active = chart.getActiveRenderer ? chart.getActiveRenderer() : 'svg'
    el.innerHTML =
      'Cells: ' +
      cellCount.toLocaleString() +
      '  ·  Active renderer: ' +
      active.toUpperCase() +
      '  ·  DOM nodes in chart: ' +
      domNodeCount().toLocaleString() +
      '  ·  Render: ' +
      (lastRenderMs > 0 ? lastRenderMs + ' ms' : 'change a control to time it') +
      ''
  }

  function rebuild() {
    cellCount = parseInt(document.getElementById('cellCount').value, 10)
    var mode = document.getElementById('rendererMode').value

    heatmapData = generateHeatmap(cellCount)
    options.chart.renderer = mode
    options.series = heatmapData
    options.title.text = 'Heatmap: ' + cellCount.toLocaleString() + ' cells'

    var t = performance.now()
    if (chart) chart.destroy()
    chart = new ApexCharts(document.querySelector('#chart'), options)
    me.heatmapChart = chart
    chart.render().then(function () {
      if (me.heatmapDisposed) return
      lastRenderMs = Math.round(performance.now() - t)
      updateStats()
    })
  }

  document.getElementById('rerender').addEventListener('click', rebuild)
  document.getElementById('rendererMode').addEventListener('change', rebuild)
  document.getElementById('cellCount').addEventListener('change', rebuild)

  chart = new ApexCharts(document.querySelector('#chart'), options)
  me.heatmapChart = chart
  chart.render().then(function () {
    if (me.heatmapDisposed) return
    updateStats()
  })
},
beforeDestroy: function () {
  this.heatmapDisposed = true
  if (this.heatmapChart) this.heatmapChart.destroy()
},
